package main

import (
	"bytes"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// findTitle recursively searches for the first <title> tag and returns its text content
func findTitle(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "title" {
		return nodeText(n)
	}
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if title := findTitle(c); title != "" {
			return title
		}
	}
	return ""
}

// findMetaDescription recursively searches for <meta name="description"> and returns its content attribute
func findMetaDescription(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "meta" {
		var nameVal, contentVal string
		for _, attr := range n.Attr {
			if attr.Key == "name" {
				nameVal = attr.Val
			} else if attr.Key == "content" {
				contentVal = attr.Val
			}
		}
		if strings.EqualFold(nameVal, "description") && contentVal != "" {
			return contentVal
		}
	}
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if desc := findMetaDescription(c); desc != "" {
			return desc
		}
	}
	return ""
}

// nodeText recursively collects all text content from a node subtree
func nodeText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result strings.Builder
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result.WriteString(nodeText(c))
	}
	return result.String()
}

// FetchURLPreview handles POST /preview requests to fetch and parse URL metadata
func FetchURLPreview(ctx echo.Context) error {
	// Parse request body
	var req struct {
		URL string `json:"url"`
	}
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid JSON body"})
	}

	// Validate URL presence and format
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
	}
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid URL format"})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "only HTTP/HTTPS URLs allowed"})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with User-Agent header to avoid blocking
	httpReq, err := http.NewRequest("GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "request creation failed"})
	}
	httpReq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Execute HTTP request
	resp, err := client.Do(httpReq)
	if err != nil {
		if urlErr, ok := err.(*url.Error); ok && urlErr.Timeout() {
			return ctx.JSON(http.StatusGatewayTimeout, map[string]string{"error": "URL fetch timeout"})
		}
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Validate HTTP status code
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(http.StatusBadGateway, map[string]string{
			"error": fmt.Sprintf("unexpected status code: %d", resp.StatusCode),
		})
	}

	// Limit response body to 1MB to prevent memory issues
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "failed to read response"})
	}

	// Parse HTML content
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "HTML parsing failed"})
	}

	// Extract and clean metadata
	title := strings.TrimSpace(findTitle(doc))
	description := strings.TrimSpace(findMetaDescription(doc))

	// Return JSON response
	return ctx.JSON(http.StatusOK, map[string]string{
		"title":       title,
		"description": description,
	})
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

