		*stdDesc = contentVal
	} else if propVal == "og:description" && *ogDesc == "" {
		*ogDesc = contentVal
	}
}

// getFinalDescription prioritizes standard description over Open Graph
func getFinalDescription(stdDesc, ogDesc string) string {
	if stdDesc != "" {
		return stdDesc
	}
	return ogDesc
}

