		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("HTTP %d: Failed to retrieve page", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractMetadata(body)

	return ctx.JSON(http.StatusOK, map[string]string{
		"title":       title,
		"description": description,
	})
}

func extractMetadata(body []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", ""
	}

	var title string
	var ogDescription string
	var normalDescription string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				title = getText(n)
			}
			if n.Data == "meta" {
				name := getAttr(n, "name")
				property := getAttr(n, "property")
				content := getAttr(n, "content")
				if content != "" {
