package main

import (
	"html"
	"io"
	"net/http"
	"net/url"
	"regexp"
	"time"

	"github.com/labstack/echo/v4"
)

type URLRequest struct {
	URL string `json:"url"`
}

type URLPreview struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid JSON body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
	}

	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid URL format"})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "only HTTP and HTTPS URLs are allowed"})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		if urlErr, ok := err.(*url.Error); ok && urlErr.Timeout() {
			return ctx.JSON(http.StatusGatewayTimeout, map[string]string{"error": "URL fetch timeout"})
		}
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "failed to fetch page, status code: " + resp.Status})
	}

	bodyBytes, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024)) // 1MB limit
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to read response body"})
	}
	bodyStr := string(bodyBytes)

	// Extract title (case-insensitive, dotall mode)
	title := ""
	titlePattern := regexp.MustCompile(`(?is)<title>(.*?)</title>`)
	if matches := titlePattern.FindStringSubmatch(bodyStr); len(matches) > 1 {
		title = html.UnescapeString(matches[1])
	}

	// Extract description: prefer Open Graph description
	description := ""
	ogPattern := regexp.MustCompile(`(?i)<meta[^>]*property=["']og:description["'][^>]*content=["']([^"']*)["']`)
	if matches := ogPattern.FindStringSubmatch(bodyStr); len(matches) > 1 {
		description = html.UnescapeString(matches[1])
	} else {
		descPattern := regexp.MustCompile(`(?i)<meta[^>]*name=["']description["'][^>]*content=["']([^"']*)["']`)
		if matches := descPattern.FindStringSubmatch(bodyStr); len(matches) > 1 {
			description = html.UnescapeString(matches[1])
		}
	}

	return ctx.JSON(http.StatusOK, URLPreview{
		Title:       title,
		Description: description,
	})
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Start(":8080")
}

