package main

import (
	"bytes"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// PreviewRequest represents the expected JSON input
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the JSON output
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

// FetchURLPreview handles POST /preview requests
func FetchURLPreview(ctx echo.Context) error {
	// Parse request body
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Create context-aware HTTP request with timeout
	client := &http.Client{Timeout: 3 * time.Second}
	httpReq, err := http.NewRequestWithContext(
		ctx.Request().Context(),
		http.MethodGet,
		parsedURL.String(),
		nil,
	)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch URL content
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Read response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Extract title and description from HTML
	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML to extract title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	// Recursive tree traversal to find title and description
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Stop early if both values are found
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract page title (first occurrence)
			if n.Data == "title" && title == "" {
				title = getText(n)
				title = strings.TrimSpace(title)
			}

			// Extract meta description (prioritize standard name="description")
			if n.Data == "meta" && description == "" {
				hasNameDesc := false
				contentVal := ""

				// First pass: check for name="description"
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
						hasNameDesc = true
					}
					if attr.Key == "content" {
						contentVal = attr.Val
					}
				}
				if hasNameDesc && contentVal != "" {
					description = contentVal
					return
				}

				// Second pass: check for Open Graph description if standard not found
				hasOGDesc := false
				contentVal = ""
				for _, attr := range n.Attr {
					if attr.Key == "property" && strings.EqualFold(attr.Val, "og:description") {
						hasOGDesc = true
					}
					if attr.Key == "content" {
						contentVal = attr.Val
					}
				}
				if hasOGDesc && contentVal != "" {
					description = contentVal
				}
			}
		}

		// Continue traversal to children
		for c := n.FirstChild; c != nil && (title == "" || description == ""); c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return strings.TrimSpace(title), strings.TrimSpace(description)
}

// getText recursively collects text content from a node and its children
func getText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var builder strings.Builder
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		builder.WriteString(getText(c))
	}
	return builder.String()
}

