func parseHTML(body []byte) (string, string) {
	var title, description string
	foundTitle := false
	foundDesc := false

	tokenizer := html.NewTokenizer(bytes.NewReader(body))
	for {
		if foundTitle && foundDesc {
			break
		}

		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			return title, description
		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()
			tagName := token.Data

			if !foundTitle && tagName == "title" {
				if tokenizer.Next() == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
					foundTitle = true
				}
			} else if tagName == "meta" && !foundDesc {
				attrs := make(map[string]string)
				for _, attr := range token.Attr {
					attrs[attr.Key] = attr.Val
				}
				if (attrs["name"] == "description" || attrs["property"] == "og:description") && attrs["content"] != "" {
					description = strings.TrimSpace(attrs["content"])
					foundDesc = true
				}
			}
		}
	}
	return title, description
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid JSON body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
	}

	parsedURL, err := url.ParseRequestURI(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid URL format"})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "only http and https URLs are allowed"})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	httpReq, err := http.NewRequestWithContext(
		context.Background(),
		http.MethodGet,
		req.URL,
		nil,
	)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "URLPreviewBot/1.0 (+https://example.com/bot)")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "failed to fetch URL content"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "received non-200 response from URL"})
	}

