	"golang.org/x/net/html"
)

type previewRequest struct {
	URL string `json:"url"`
}

type previewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req previewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid JSON body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
	}

	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL scheme must be http or https"})
	}
	if parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL must contain a valid host"})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{
			"error": fmt.Sprintf("unexpected HTTP status: %d", resp.StatusCode),
		})
	}

	title, description := extractMetadata(resp.Body)
	return ctx.JSON(http.StatusOK, previewResponse{
		Title:       title,
		Description: description,
	})
}

func extractMetadata(r io.Reader) (string, string) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", ""
	}

	var title, description string
	var visit func(*html.Node)
	visit = func(n *html.Node) {
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				title = strings.TrimSpace(getText(n))
				return
			}

			if n.Data == "meta" && description == "" {
				var hasDescription bool
				var contentVal string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						hasDescription = true
					}
					if attr.Key == "content" {
						contentVal = attr.Val
					}
				}
				if hasDescription {
					description = contentVal
					return
				}
			}
		}

		for child := n.FirstChild; child != nil; child = child.NextSibling {
			visit(child)
			if title != "" && description != "" {
				break
			}
		}
	}
	visit(doc)
	return title, description
}

func getText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result string
	for child := n.FirstChild; child != nil; child = child.NextSibling {
		result += getText(child)
	}
	return result
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	if err := e.Start(":8080"); err != nil {
		panic(err)
	}
}

