// PreviewRequest represents the expected JSON input
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the JSON output
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

// FetchURLPreview handles POST /preview requests
func FetchURLPreview(ctx echo.Context) error {
	// Parse and validate request body
	reqBody := new(PreviewRequest)
	if err := ctx.Bind(reqBody); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON payload"})
	}

	// Validate URL structure
	parsedURL, err := url.Parse(reqBody.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	// Enforce security constraints
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}
	if parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL must contain a valid host"})
	}

	// Create context-aware HTTP request
	httpReq, err := http.NewRequestWithContext(
		ctx.Request().Context(),
		http.MethodGet,
		reqBody.URL,
		nil,
	)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to construct HTTP request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Configure HTTP client with timeout
	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL content"})
	}
	defer resp.Body.Close()

	// Validate HTTP response status
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": fmt.Sprintf("Remote server returned status %d", resp.StatusCode),
		})
	}

	// Limit response body size to prevent abuse (1MB)
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Extract title and description from HTML
	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML to retrieve title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title, description string

	var visit func(*html.Node)
	visit = func(n *html.Node) {
		// Stop traversal if both values are found
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract page title (first occurrence)
			if n.Data == "title" && title == "" {
				title = strings.TrimSpace(getText(n))
				return // Title found, no need to traverse children
			}

			// Extract meta description (first valid occurrence)
			if n.Data == "meta" && description == "" {
				hasNameDesc := false
				var contentVal string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						if strings.EqualFold(attr.Val, "description") {
							hasNameDesc = true
						}
					case "content":
						contentVal = attr.Val
					}
				}
				if hasNameDesc && contentVal != "" {
					description = strings.TrimSpace(contentVal)
				}
				return // Meta tags are self-contained
			}
		}

		// Recursively traverse children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			visit(c)
			// Early termination check
			if title != "" && description != "" {
				return
			}
		}
	}

	visit(doc)
	return title, description
}

// getText recursively extracts text content from an HTML node
func getText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result strings.Builder
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result.WriteString(getText(c))
	}
	return result.String()
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)

	// Start server with error handling
	if err := e.Start(":8080"); err != nil && err != http.ErrServerClosed {
		log.Fatalf("Failed to start server: %v", err)
	}
}

