package main

import (
	"fmt"
	"html"
	"io"
	"net/http"
	"net/url"
	"regexp"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
)

// extractTitle finds the first <title> tag content in HTML body
func extractTitle(body string) string {
	re := regexp.MustCompile(`(?i)<title[^>]*>(.*?)</title>`)
	matches := re.FindStringSubmatch(body)
	if len(matches) > 1 {
		return html.UnescapeString(strings.TrimSpace(matches[1]))
	}
	return ""
}

// extractDescription finds the content of the first meta description tag
func extractDescription(body string) string {
	// Find meta tags containing name="description" (case-insensitive, attributes in any order)
	metaTagRe := regexp.MustCompile(`(?i)<meta[^>]*name=["']description["'][^>]*>`)
	metaTags := metaTagRe.FindAllString(body, 1)
	if len(metaTags) == 0 {
		return ""
	}

	// Extract content attribute from the matched meta tag
	contentRe := regexp.MustCompile(`(?i)content=["']([^"']*)["']`)
	contentMatches := contentRe.FindStringSubmatch(metaTags[0])
	if len(contentMatches) > 1 {
		return html.UnescapeString(strings.TrimSpace(contentMatches[1]))
	}
	return ""
}

func FetchURLPreview(ctx echo.Context) error {
	// Define request structure
	type Request struct {
		URL string `json:"url" validate:"required"`
	}

	var req Request
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "invalid JSON body",
		})
	}

	// Validate URL presence
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "url field is required",
		})
	}

	// Parse and validate URL structure
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "invalid URL format",
		})
	}

	// Security/validation: only allow http/https schemes and require host
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "only HTTP and HTTPS URLs are allowed",
		})
	}
	if parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "URL must contain a valid host",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with User-Agent header to avoid blocking
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "failed to create request",
		})
	}
	httpReq.Header.Set("User-Agent", "URLPreviewBot/1.0 (+https://example.com/preview)")

	// Fetch the URL
	resp, err := client.Do(httpReq)
	if err != nil {
		status := http.StatusBadGateway
		if strings.Contains(err.Error(), "timeout") || strings.Contains(err.Error(), "context deadline") {
			status = http.StatusGatewayTimeout
		}
		return ctx.JSON(status, map[string]string{
			"error": fmt.Sprintf("failed to fetch URL: %v", err),
		})
	}
	defer resp.Body.Close()

	// Check HTTP status code
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{
			"error": fmt.Sprintf("remote server returned status %d", resp.StatusCode),
		})
	}

	// Limit response body to 1MB to prevent memory issues
	bodyBytes, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{
			"error": "failed to read response body",
		})
	}

	bodyStr := string(bodyBytes)
	title := extractTitle(bodyStr)
	description := extractDescription(bodyStr)

	// Return extracted metadata
	return ctx.JSON(http.StatusOK, map[string]string{
		"url":         req.URL,
		"title":       title,
		"description": description,
	})
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)

	// Start server on port 8080
	e.Logger.Fatal(e.Start(":8080"))
}

