// getText recursively extracts text content from an HTML node
func getText(n *html.Node) string {
    if n.Type == html.TextNode {
        return n.Data
    }
    var result strings.Builder
    for c := n.FirstChild; c != nil; c = c.NextSibling {
        result.WriteString(getText(c))
    }
    return result.String()
}

// visit traverses HTML nodes to extract title and description candidates
func visit(node *html.Node, data *pageData) {
    if node.Type == html.ElementNode {
        // Extract page title (first occurrence)
        if node.Data == "title" && data.title == "" {
            data.title = strings.TrimSpace(getText(node))
        }

        // Process meta tags for descriptions
        if node.Data == "meta" {
