    }

    // Validate URL presence
    if req.URL == "" {
        return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url field is required"})
    }

    // Validate URL format and scheme
    parsedURL, err := url.ParseRequestURI(req.URL)
    if err != nil {
        return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid URL format"})
    }
    if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
        return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "only HTTP/HTTPS URLs allowed"})
    }

    // Create HTTP client with 3-second timeout
    client := &http.Client{
