// extractMetadata parses HTML to extract title and meta description
func extractMetadata(body io.Reader) (string, string, error) {
	doc, err := html.Parse(body)
	if err != nil {
		return "", "", err
	}

	var title string
	var description string

	var visit func(*html.Node)
