	if resp.StatusCode != http.StatusOK {
		return echo.NewHTTPError(http.StatusBadGateway, fmt.Sprintf("Received non-200 status code: %d", resp.StatusCode))
	}

	title, description, err := extractMetadata(resp.Body)
	if err != nil {
		return echo.NewHTTPError(http.StatusInternalServerError, fmt.Sprintf("Failed to parse HTML: %v", err))
	}

	return ctx.JSON(http.StatusOK, map[string]string{
		"title":       title,
		"description": description,
	})
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

