package main

import (
	"fmt"
	"io"
	"net/http"
	"net/url"
	"regexp"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
)

var (
	// Pre-compiled regex patterns for HTML extraction
	titleRegex          = regexp.MustCompile(`(?i)<title>(.*?)</title>`)
	metaDescriptionRegex = regexp.MustCompile(`(?i)<meta[^>]*name=["']description["'][^>]*content=["']([^"']*)["']`)
	ogDescriptionRegex   = regexp.MustCompile(`(?i)<meta[^>]*property=["']og:description["'][^>]*content=["']([^"']*)["']`)
)

// PreviewRequest defines the expected JSON request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the JSON response structure
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

// FetchURLPreview handles POST /preview requests to fetch and parse URL previews
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Create HTTP client with timeout and safety limits
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create properly formed HTTP request
	httpReq, err := http.NewRequest(http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Invalid URL for request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute request and handle errors
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": fmt.Sprintf("Target URL returned HTTP %d", resp.StatusCode)})
	}

	// Limit response body to 1MB to prevent memory exhaustion
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML content to extract title and description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	htmlStr := string(htmlContent)

	// Extract title from first matching <title> tag
	titleMatches := titleRegex.FindStringSubmatch(htmlStr)
	var title string
	if len(titleMatches) > 1 {
		title = strings.TrimSpace(titleMatches[1])
	}

	// Attempt standard meta description first
	descMatches := metaDescriptionRegex.FindStringSubmatch(htmlStr)
	var description string
	if len(descMatches) > 1 && descMatches[1] != "" {
		description = strings.TrimSpace(descMatches[1])
	} else {
		// Fall back to Open Graph description
		descMatches = ogDescriptionRegex.FindStringSubmatch(htmlStr)
		if len(descMatches) > 1 && descMatches[1] != "" {
			description = strings.TrimSpace(descMatches[1])
		}
	}

	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

