		if desc := extractDescription(c); desc != "" {
			return desc
		}
	}
	return ""
}

func FetchURLPreview(ctx echo.Context) error {
	type Request struct {
		URL string `json:"url"`
	}
	var reqBody Request
	if err := ctx.Bind(&reqBody); err != nil {
		return ctx.JSON(http.StatusBadRequest, echo.Map{"error": "invalid JSON payload"})
	}

	urlStr := strings.TrimSpace(reqBody.URL)
	if urlStr == "" {
		return ctx.JSON(http.StatusBadRequest, echo.Map{"error": "url field is required"})
	}
	if !strings.HasPrefix(urlStr, "http://") && !strings.HasPrefix(urlStr, "https://") {
		return ctx.JSON(http.StatusBadRequest, echo.Map{"error": "url must start with http:// or https://"})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	reqHTTP, err := http.NewRequest("GET", urlStr, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, echo.Map{"error": "invalid URL format"})
	}
	reqHTTP.Header.Set("User-Agent", "URLPreviewBot/1.0")

	resp, err := client.Do(reqHTTP)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, echo.Map{"error": "failed to fetch URL: " + err.Error()})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, echo.Map{"error": fmt.Sprintf("unexpected HTTP status: %d", resp.StatusCode)})
	}

	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, echo.Map{"error": "failed to parse HTML content"})
	}

	title := extractTitle(doc)
	description := extractDescription(doc)

	return ctx.JSON(http.StatusOK, echo.Map{
		"title":       title,
		"description": description,
	})
}

