func FetchURLPreview(ctx echo.Context) error {
	// Bind and validate request body
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, "invalid JSON body")
	}
	if req.URL == "" {
		return echo.NewHTTPError(http.StatusBadRequest, "url field is required")
	}

	// Validate URL scheme
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, "invalid URL format")
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return echo.NewHTTPError(http.StatusBadRequest, "only http and https URLs are allowed")
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with User-Agent header (prevents blocking by some servers)
	httpReq, err := http.NewRequestWithContext(ctx.Request().Context(), "GET", req.URL, nil)
	if err != nil {
		return echo.NewHTTPError(http.StatusBadRequest, "invalid URL")
	}
	httpReq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Fetch URL content
	resp, err := client.Do(httpReq)
	if err != nil {
		return echo.NewHTTPError(http.StatusBadGateway, fmt.Sprintf("fetch failed: %v", err))
	}
	defer resp.Body.Close()

	// Validate HTTP status code (must be 2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return echo.NewHTTPError(http.StatusBadGateway, fmt.Sprintf("unexpected status code: %d", resp.StatusCode))
	}

	// Limit response body to 1MB to prevent DoS
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
	if err != nil {
		return echo.NewHTTPError(http.StatusBadGateway, "failed to read response body")
	}

	// Parse HTML content
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return echo.NewHTTPError(http.StatusBadGateway, "invalid HTML content")
	}

	// Extract title and description
	var title string
	var description string

	// Helper: extract text content from node subtree
	var getText func(*html.Node) string
	getText = func(n *html.Node) string {
		if n.Type == html.TextNode {
			return n.Data
		}
		var result strings.Builder
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			result.WriteString(getText(c))
		}
		return result.String()
	}

	// Traverse DOM to find title and meta description
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Stop early if both values are already found
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract page title
			if n.Data == "title" && title == "" {
