		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL must use http or https scheme"})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with context and User-Agent header
	httpReq, err := http.NewRequestWithContext(context.Background(), http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL"})
	}
	httpReq.Header.Set("User-Agent", "EchoURLPreviewBot/1.0 (+https://example.com/preview)")

	// Fetch URL content
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	// Check HTTP status code
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("Received non-200 status: %d", resp.StatusCode)})
	}

	// Limit response body to 1MB and read
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to read response body"})
	}

	// Parse HTML
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML content"})
	}

	// Extract title and description
	title := findTitle(doc)
	description := findMetaDescriptionByName(doc)
	if description == "" {
		description = findMetaDescriptionByProperty(doc)
	}

	// Return JSON response
	return ctx.JSON(http.StatusOK, map[string]string{
		"title":       strings.TrimSpace(title),
		"description": strings.TrimSpace(description),
	})
}

// findTitle recursively searches for the first <title> tag and returns its text content
func findTitle(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "title" {
		return textContent(n)
	}
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if result := findTitle(c); result != "" {
			return result
		}
	}
	return ""
}

// findMetaDescriptionByName searches for <meta name="description"> tag
func findMetaDescriptionByName(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "meta" {
		var hasTarget bool
		var content string
		for _, attr := range n.Attr {
			if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
				hasTarget = true
			}
			if attr.Key == "content" {
				content = attr.Val
			}
		}
		if hasTarget && content != "" {
			return content
		}
	}
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if desc := findMetaDescriptionByName(c); desc != "" {
			return desc
		}
	}
	return ""
}

// findMetaDescriptionByProperty searches for <meta property="og:description"> tag
func findMetaDescriptionByProperty(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "meta" {
		var hasTarget bool
		var content string
		for _, attr := range n.Attr {
			if attr.Key == "property" && strings.ToLower(attr.Val) == "og:description" {
				hasTarget = true
			}
			if attr.Key == "content" {
				content = attr.Val
			}
		}
		if hasTarget && content != "" {
			return content
		}
	}
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if desc := findMetaDescriptionByProperty(c); desc != "" {
			return desc
		}
	}
	return ""
}

// textContent recursively collects all text node content under given node
func textContent(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result strings.Builder
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result.WriteString(textContent(c))
	}
	return result.String()
}

