// PreviewRequest represents the expected JSON request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the JSON response structure
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

// FetchURLPreview handles POST /preview requests to fetch and parse URL metadata
func FetchURLPreview(ctx echo.Context) error {
	// Parse and validate request body
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON payload"})
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	// Create HTTP client with timeout and context propagation
	client := &http.Client{Timeout: 3 * time.Second}
	httpReq, err := http.NewRequestWithContext(
		ctx.Request().Context(),
		http.MethodGet,
		parsedURL.String(),
		nil,
	)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create HTTP request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch URL content
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL content"})
	}
	defer resp.Body.Close()

	// Check HTTP status
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("Unexpected HTTP status: %d", resp.StatusCode)})
	}

	// Read response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Extract metadata from HTML
	title, description := extractTitleAndDescription(body)

	// Return structured response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractTitleAndDescription parses HTML to extract title and meta description
func extractTitleAndDescription(htmlContent []byte) (string, string) {
	if len(htmlContent) == 0 {
		return "", ""
	}

	z := htmlparser.NewTokenizer(bytes.NewReader(htmlContent))
	var title, description string
	inTitle := false
	titleDone := false
	descDone := false

	for {
		// Early exit if both values are found
		if titleDone && descDone {
			break
		}

		tt := z.Next()
		switch tt {
		case htmlparser.ErrorToken:
			// End of document or parse error
			return strings.TrimSpace(title), strings.TrimSpace(description)
		case htmlparser.StartTagToken:
			token := z.Token()
			if token.Data == "title" && !titleDone {
				inTitle = true
			}
		case htmlparser.TextToken:
			if inTitle && !titleDone {
				// Accumulate and unescape HTML entities in title text
				title += html.UnescapeString(z.Token().Data)
			}
		case htmlparser.EndTagToken:
			token := z.Token()
			if token.Data == "title" && inTitle {
				inTitle = false
				titleDone = true
			}
		case htmlparser.SelfClosingTagToken:
			token := z.Token()
			if token.Data == "meta" && !descDone {
				var nameAttr, contentAttr string
				for _, attr := range token.Attr {
					switch attr.Key {
					case "name":
						nameAttr = attr.Val
					case "content":
						contentAttr = attr.Val
					}
				}
				// Case-insensitive match for standard meta description
				if strings.EqualFold(nameAttr, "description") && contentAttr != "" {
					description = contentAttr
					descDone = true
				}
			}
		}
	}

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

// main initializes the Echo server and registers routes
func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

